/**
 * @summary List recruiter notes for a candidate (optionally scoped to a job)
 */
export const getListCandidateNotesUrl = (
  candidateId: number,
  params?: ListCandidateNotesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/candidates/${candidateId}/notes?${stringifiedParams}`
    : `/api/candidates/${candidateId}/notes`;
};

